		end)

		local function sanitizeFileName(str)
			str = string.gsub(str, "[^%w_]+", "_")
			str = string.gsub(str, "_+", "_")
			str = string.gsub(str, "^_+", "")
			str = string.gsub(str, "_+$", "")
			return string.sub(str, 1, 240)
		end

		if ToSaveInstance then
			if mode == "optimized" then  
